-- ============================================================================
-- NexaCare / Whitegum — LPM teaching content (Weeks 1-8 + cross-cutting)
-- Companion to nexacare_seed.sql. Adds the legal-project-management workflows,
-- governance/risk playbooks, and a Regwatch watch that let students do each
-- LAWS8198 week's activity inside Mike. Research/education only.
--
-- HOW TO USE
-- 1. Replace 00000000-0000-0000-0000-000000000000 with the owner's Supabase
--    auth user id (same account that owns nexacare_seed.sql content).
-- 2. Run in the Supabase SQL editor.
-- 3. Import seed/clauses_lpm_templates.csv via /clauses -> Import CSV (UI) so
--    the 6 template clauses get embeddings. Do NOT insert those by SQL.
--
-- Already installed on the live instance for owner
-- a3e483e5-0e15-4eec-9bac-a41e364a7e30 on 2026-07-23.
-- ============================================================================

-- ---------------------------------------------------------------------------
-- Playbooks: GenAI governance (SC Gen 23 + joint AI Statement) + Risk/quality
-- ---------------------------------------------------------------------------
insert into public.playbooks (id, owner_id, name, agreement_type, description) values
('22222222-0004-4111-8111-111111111111','00000000-0000-0000-0000-000000000000','GenAI in NSW legal practice — governance','other','Governance checklist encoding NSW Supreme Court Practice Note SC Gen 23 (commenced 3 Feb 2025) and the joint Statement on the use of AI in Australian legal practice (Law Society of NSW / VLSB+C / LPB WA, 6 Dec 2024). Run Mike outputs against it. Rules repurpose the negotiation-playbook schema: preferred = compliant practice, acceptable_fallback = minimum acceptable, dealbreaker = prohibited. Verify current source wording before real use.'),
('22222222-0005-4111-8111-111111111111','00000000-0000-0000-0000-000000000000','Right-sourcing risk & quality gates','other','Quality checkpoints and a risk-acceptance ladder for disaggregated, delegated and outsourced legal work. Pairs with the Right-sourcing analysis workflow (Week 5).')
on conflict (id) do nothing;

insert into public.playbook_rules (playbook_id, position, topic, preferred, acceptable_fallback, dealbreaker, severity, notes) values
('22222222-0004-4111-8111-111111111111',1,'Citation & authority verification','Every case, statute, quotation and cross-reference is independently verified against the primary source before an output is filed or sent, and the verification is performed by a person, not by a generative AI tool.','At minimum, all citations are checked against an authoritative legal database and the check is logged on the matter.','Relying on a generative AI tool to confirm that AI-produced citations are real or accurate.','high','SC Gen 23 requires verification of all citations and states it cannot be done using GenAI. Mirrors Mike human self-validation gate.'),
('22222222-0004-4111-8111-111111111111',2,'AI-generated evidence','No generative AI is used to produce the content of affidavits, witness statements, or the substance of an expert report.','Any AI assistance touching an expert report is used only with prior leave of the court and is disclosed.','Passing AI-drafted material off as a witness own evidence, or using AI to alter the substance of evidence.','high','SC Gen 23 prohibitions on AI in evidence and expert reports.'),
('22222222-0004-4111-8111-111111111111',3,'Confidentiality & client data','No confidential, privileged or personal client information is entered into an AI tool that lacks appropriate confidentiality and data-handling assurances (including no-training terms).','Only tools with contractual confidentiality and Australian-privacy-consistent handling are used, and only the minimum data needed.','Pasting client or patient data into a public consumer AI tool.','high','APP obligations (Privacy Act 1988 (Cth)); Solicitor Guide to Responsible Use of AI. Acute for NexaCare health data.'),
('22222222-0004-4111-8111-111111111111',4,'Independent professional judgment','AI output is treated as a draft over which the lawyer exercises independent judgment; the lawyer owns and is responsible for the result.','All AI-assisted work product receives substantive lawyer review before it is used or sent.','Delivering AI output to a client or court without a lawyer having reviewed and adopted it.','high','Joint AI Statement — AI is not a substitute for legal knowledge, experience or expertise.'),
('22222222-0004-4111-8111-111111111111',5,'Competence & supervision','Users understand the capabilities and limits of the tool they are using, and juniors AI-assisted work is supervised.','Documented training and defined review checkpoints for AI-assisted work.','Unsupervised reliance on AI beyond the user competence to check it.','medium','Supervision and competence duties; connects to Week-2 delegation and Week-7 ethics.'),
('22222222-0004-4111-8111-111111111111',6,'Disclosure & costs','The firm is transparent, where required, about AI use, and reflects AI-driven efficiency fairly in how the matter is priced and billed.','An internal record of AI use per matter is maintained.','Billing time as if worked manually where AI did the work, in a way that misleads the client.','medium','Links to value pricing (Week 1) and Rogers & Dombkins on LPM ethics (Week 7).'),
('22222222-0005-4111-8111-111111111111',1,'Ownership of outsourced output','A named firm reviewer is accountable for every disaggregated, delegated or outsourced deliverable before it reaches the client.','Risk-based sample QA at a defined rate for lower-risk, high-volume work.','Outsourced or AI-generated work reaching the client without a firm reviewer.','high','Quality management for LPO / ALSP work (Lacity, Willcocks & Burgess, Week 5).'),
('22222222-0005-4111-8111-111111111111',2,'Data & confidentiality boundary','What may leave the firm is explicitly defined, and client consent is obtained before offshore or ALSP handling of identifiable data.','De-identified or redacted data only where consent is not in place.','Transferring identifiable client data to a third party without consent or an adequate data agreement.','high','Interlocks with GenAI governance rule 3 and NexaCare health-data sensitivity.'),
('22222222-0005-4111-8111-111111111111',3,'Quality gates','Each phase has defined entry and exit criteria and an acceptance checklist before work moves on.','Partner sign-off at each billing milestone.','No acceptance criteria — work moves on unchecked.','medium','Stage-gates align to the fixed-fee milestones.'),
('22222222-0005-4111-8111-111111111111',4,'Right-sourcing rationale','Each task sourcing model (keep / delegate / paralegal / commoditise / ALSP / automate) is justified against risk, complexity and cost.','A documented default model per task type.','Judgment-heavy or highly sensitive tasks outsourced or fully automated.','medium','Feeds from the Right-sourcing analysis workflow.'),
('22222222-0005-4111-8111-111111111111',5,'Performance metrics','SLAs and KPIs are set and tracked for outsourced work, with a feedback loop to the provider.','Periodic review of provider performance.','No measurement of outsourced quality or timeliness.','low','Demonstrating and improving value (Week 5 readings).');

-- ---------------------------------------------------------------------------
-- Regwatch: AI, privacy & the legal profession (closest available feeds).
-- NOTE: SC Gen 23 / Law Society protocols are not government-RSS sources, so
-- they remain a manual-tracking item under the project no-scrape rule.
-- ---------------------------------------------------------------------------
insert into public.regulatory_watches (owner_id, name, topics, jurisdictions, sources, active) values
('00000000-0000-0000-0000-000000000000','AI, privacy & the legal profession',
 array['generative AI','artificial intelligence','automated decision-making','privacy','Australian Privacy Principles','data protection','legal technology','professional conduct'],
 array['Cth','NSW'], array['oaic_news','frl_new_acts'], true);

-- ---------------------------------------------------------------------------
-- LPM workflows (assistant, approval-gated plan templates). Tool allowlists
-- are derived server-side from each step role, so plan_template only needs
-- role / instruction / depends_on.
-- ---------------------------------------------------------------------------
insert into public.workflows (id, user_id, title, type, prompt_md, practice, jurisdictions, plan_template) values
('33333333-0006-4111-8111-111111111111','00000000-0000-0000-0000-000000000000','Scope a matter from a client brief (W1)','assistant','Turn the client brief and engagement materials into a project scope: a phased work-breakdown structure, assumptions, out-of-scope list, and a fixed-fee milestone plan. Legal project management exercise for the Kendry & Slate / NexaCare matter.','Legal Project Management',array['NSW','QLD','Cth'],
'{"title":"Scope a matter from a client brief","steps":[{"position":1,"depends_on":[],"role":"intake","instruction":"Read the client brief and engagement materials in the matter documents. Extract: the client objectives, transaction scope, key dates and deadlines, commercial drivers, constraints, and the fee model (fixed fee with milestone billing and a 10% holdback). Capture any hard dates as deadline items on the matter list."},{"position":2,"depends_on":[1],"role":"drafting","instruction":"Produce a phased work-breakdown structure across the five phases (Scoping, Due Diligence, Documentation and Negotiation, Post-Execution, Post-Closing). For each task give a short description, the responsible role by seniority (partner / senior associate / junior / paralegal), and an effort estimate in hours. Then add: an assumptions register, an explicit out-of-scope list, and a fixed-fee milestone breakdown mapped to the four billing milestones (DD and risk report; SPA signing; lease-consent readiness; completion including a day-one readiness pack) with the 10% completion holdback noted."},{"position":3,"depends_on":[2],"role":"review","instruction":"Check the WBS against the five phases and flag any missing workstream (EHR / data migration, landlord consents, transitional services, employment transfer, privacy and OAIC). Flag scope-creep risks and any milestone whose effort looks materially under- or over-estimated."}]}'::jsonb),
('33333333-0007-4111-8111-111111111111','00000000-0000-0000-0000-000000000000','Stakeholder update — persona-tuned (W2)','assistant','Draft a single matter update rewritten for three NexaCare stakeholders in their own communication styles. Teams and communication exercise.','Legal Project Management',array['NSW','QLD','Cth'],
'{"title":"Stakeholder update — persona-tuned","steps":[{"position":1,"depends_on":[],"role":"research","instruction":"Review the matter list and recent status, and identify the key update to communicate this week (for example the EHR vendor position, landlord consent progress, or the accelerated timetable). Summarise the facts in three or four bullet points."},{"position":2,"depends_on":[1],"role":"drafting","instruction":"Draft the same update three ways, each under 200 words. (1) Dr Alexandra Keller, CEO — commercial, decisive, outcome-first, lead with the bottom line and the decision needed. (2) Jonathan Wu, General Counsel — disciplined and risk-weighted, no surprises, use headings, state the risk position and options. (3) Daniel Okoye, CIO — precise and technical, focus on operational continuity, cutover and data integrity. Do not invent facts beyond the summary."},{"position":3,"depends_on":[2],"role":"review","instruction":"Check each version fits the intended persona and that no material risk has been dropped for brevity (Stop the Line). Note where a message may need partner sign-off before sending."}]}'::jsonb),
('33333333-0008-4111-8111-111111111111','00000000-0000-0000-0000-000000000000','Map and diagnose a process — SIPOC + waste (W3)','assistant','Map the matter process and diagnose pain points using SIPOC and a Lean waste scan. Process optimisation exercise.','Legal Project Management',array['NSW','QLD','Cth'],
'{"title":"Map and diagnose a process (SIPOC + waste)","steps":[{"position":1,"depends_on":[],"role":"research","instruction":"Using the M&A process map and the work-breakdown structure, produce a SIPOC for the matter: Suppliers, Inputs, the main Process steps, Outputs, and Customers. Keep the process steps at a readable level (10 to 15 steps)."},{"position":2,"depends_on":[1],"role":"drafting","instruction":"Overlay a Lean waste scan on the process: identify waiting, unnecessary handoffs, rework loops, over-processing, and unclear ownership. Rank the pain points by client impact and frequency, and present as a table."},{"position":3,"depends_on":[2],"role":"review","instruction":"Confirm each pain point is evidenced by the process, remove any that are speculative, and recommend the top three candidates for improvement with a one-line reason each."}]}'::jsonb),
('33333333-0009-4111-8111-111111111111','00000000-0000-0000-0000-000000000000','Design-thinking ideation (W3)','assistant','Apply design thinking to a chosen process pain point: How-Might-We statements and a prioritised solution shortlist. Design thinking exercise. State the pain point in your request.','Legal Project Management',array['General'],
'{"title":"Design-thinking ideation","steps":[{"position":1,"depends_on":[],"role":"drafting","instruction":"For the pain point described in the request, write three or four How-Might-We statements, then brainstorm a shortlist of solution ideas (people, process and technology options). Plot each idea on an impact-by-effort matrix and label it Quick Win, Big Bet, Fill-in, or Money Pit."},{"position":2,"depends_on":[1],"role":"review","instruction":"Pressure-test feasibility against the firm and matter context, then recommend one Quick Win and one Big Bet, each with concrete next steps and a success measure."}]}'::jsonb),
('33333333-000a-4111-8111-111111111111','00000000-0000-0000-0000-000000000000','User-journey map for a stakeholder (W4)','assistant','Journey-map a NexaCare stakeholder across the matter. Personas and user-journeys exercise. Name the stakeholder in your request.','Legal Project Management',array['General'],
'{"title":"User-journey map for a stakeholder","steps":[{"position":1,"depends_on":[],"role":"research","instruction":"For the stakeholder named in the request, use their persona to identify goals, concerns, and the moments that matter across the matter lifecycle."},{"position":2,"depends_on":[1],"role":"drafting","instruction":"Produce a user-journey map with columns: phase, stakeholder actions, touchpoints with the firm, pain points and emotions, and opportunities for the firm to improve the experience. Cover the journey from engagement to post-completion debrief."},{"position":3,"depends_on":[2],"role":"review","instruction":"Highlight the two or three highest-friction moments and a concrete service improvement for each."}]}'::jsonb),
('33333333-000b-4111-8111-111111111111','00000000-0000-0000-0000-000000000000','Right-sourcing analysis (W5)','assistant','Analyse the matter tasks for right-sourcing: keep, delegate, commoditise, outsource to an ALSP, or automate. Demand management and right-sourcing exercise, producing a disaggregation register.','Legal Project Management',array['General'],
'{"title":"Right-sourcing analysis","steps":[{"position":1,"depends_on":[],"role":"research","instruction":"Using the work-breakdown structure, list the matter tasks and, for each, note the skill level required, the confidentiality sensitivity, the volume, and whether it is judgment-heavy or process-heavy."},{"position":2,"depends_on":[1],"role":"drafting","instruction":"Build a disaggregation register as a table: task, current owner, recommended sourcing model (keep with partner / delegate to junior / paralegal / commoditise with a template / outsource to an ALSP / automate with Mike), rationale, and an indicative cost or risk delta. Total the tasks by model and highlight the largest efficiency opportunities."},{"position":3,"depends_on":[2],"role":"review","instruction":"Check the recommendations against the risk and quality gates playbook: confirm no judgment-heavy or highly sensitive task is outsourced, and that each outsourced item has a named firm reviewer."}]}'::jsonb),
('33333333-000c-4111-8111-111111111111','00000000-0000-0000-0000-000000000000','LPM ethics check (W7)','assistant','Run a proposed action against an LPM and AI professional-ethics checklist, surfacing where commercial pressure conflicts with professional obligations. Ethics exercise. Describe the proposed action in your request.','Legal Project Management',array['NSW','Cth'],
'{"title":"LPM ethics check","steps":[{"position":1,"depends_on":[],"role":"research","instruction":"Restate the proposed action from the request. Identify the professional-obligation touchpoints it engages: costs disclosure, scope transparency, competence, supervision of AI-assisted work, confidentiality and client data, and independent professional judgment."},{"position":2,"depends_on":[1],"role":"review","instruction":"Assess the action against each touchpoint using the GenAI governance playbook. Flag where commercial or time pressure conflicts with an obligation, rate each issue, and recommend safeguards or a modified approach. Note anything that must be escalated to a partner or that requires client consent or disclosure."}]}'::jsonb),
('33333333-000d-4111-8111-111111111111','00000000-0000-0000-0000-000000000000','Client happy-path map (W7)','assistant','Map the ideal client experience happy path for the matter, from first contact to debrief. Client experience exercise.','Legal Project Management',array['General'],
'{"title":"Client happy-path map","steps":[{"position":1,"depends_on":[],"role":"drafting","instruction":"Map the ideal client-experience journey for the matter from first contact to post-completion debrief: at each stage give the client goal, the ideal firm interaction, and the signal that tells the client things are on track. Keep the client persona (commercial, time-sensitive, wants no surprises) front of mind."},{"position":2,"depends_on":[1],"role":"review","instruction":"Contrast the happy path with the Week-2 crisis path: identify the two or three moments where the experience is most at risk under pressure, and the service safeguard that protects each."}]}'::jsonb),
('33333333-000e-4111-8111-111111111111','00000000-0000-0000-0000-000000000000','Change plan — Kotter 8-step (W8)','assistant','Produce an eight-step change-management plan (Kotter) for rolling out a change, with a stakeholder resistance map. Change management exercise. Name the change in your request.','Legal Project Management',array['General'],
'{"title":"Change plan (Kotter 8-step)","steps":[{"position":1,"depends_on":[],"role":"drafting","instruction":"For the change described in the request (for example adopting the client happy path, or rolling out Mike and LPM firm-wide), write an eight-step Kotter plan: urgency, guiding coalition, vision, communicate the vision, empower action, short-term wins, consolidate gains, anchor in culture. Give one or two concrete actions per step for the Kendry and Slate context."},{"position":2,"depends_on":[1],"role":"review","instruction":"Add a stakeholder resistance map keyed to the K&S people (for example James Bentley, cautious about unproven technology; Priya Iyer, technology-forward advocate; David O''Connell, wants audit trails). For each, note the likely stance and the tactic to bring them along. Recommend two success measures for the change."}]}'::jsonb),
('33333333-000f-4111-8111-111111111111','00000000-0000-0000-0000-000000000000','Group-assessment deliverable builder','assistant','Assemble a group analysis into a presentation-ready pack for the group assessment. Cross-cutting support for Week 9.','Legal Project Management',array['General'],
'{"title":"Group-assessment deliverable builder","steps":[{"position":1,"depends_on":[],"role":"research","instruction":"Gather the chosen analysis and any attached working documents. Identify the core argument, the supporting evidence from the matter, and the recommendation."},{"position":2,"depends_on":[1],"role":"drafting","instruction":"Assemble a presentation-ready pack: an executive summary, the analysis with headings, a clear recommendation, and an appendix of supporting detail. Use Australian English. Keep it structured for a short group presentation and note where a slide or a visual would help."},{"position":3,"depends_on":[2],"role":"review","instruction":"Check the pack for a clear line of argument, that every claim is supported, and that any legal proposition is flagged for citation verification before the presentation."}]}'::jsonb),
('33333333-0010-4111-8111-111111111111','00000000-0000-0000-0000-000000000000','Estimate & cognitive-bias register (W1)','assistant','Build an estimate register for the matter with an explicit cognitive-bias check on each estimate. Estimating exercise.','Legal Project Management',array['General'],
'{"title":"Estimate & cognitive-bias register","steps":[{"position":1,"depends_on":[],"role":"research","instruction":"Using the work-breakdown structure, list the estimable tasks or task groups for the matter."},{"position":2,"depends_on":[1],"role":"drafting","instruction":"Build an estimate register as a table: task, effort estimate (hours), basis of estimate (analogous, parametric, or expert judgment), a confidence rating, and a cognitive-bias check that names the most likely bias affecting the estimate (for example anchoring, optimism or planning-fallacy, availability) and a debiasing adjustment. Total the hours and note the three estimates carrying the most uncertainty."},{"position":3,"depends_on":[2],"role":"review","instruction":"Sense-check the totals against the fixed-fee milestone plan and flag where the estimate risks eroding the fixed fee."}]}'::jsonb)
on conflict (id) do nothing;
